    {"path": "src/app.js", "content": "const express = require('express');
const projectRouter = require('./modules/projects/routes');
const memberRouter = require('./modules/members/routes');
const taskRouter = require('./modules/tasks/routes');
const commentRouter = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectRouter);
app.use('/projects/:projectId/members', memberRouter);
app.use('/projects/:projectId/tasks', taskRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentRouter);

module.exports = app;"},
    {"path": "src/server.js", "content": "const app = require('./app');

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});"},
    {"path": "src/modules/projects/routes.js", "content": "const express = require('express');
const { createProject } = require('./service');
const router = express.Router();

router.post('/', async (req, res) => {
  const project = await createProject(req.body);
  res.status(201).json({ project });
});

module.exports = router;"},
    {"path": "src/modules/projects/service.js", "content": "const { randomUUID } = require('node:crypto');

async function createProject(data) {
  return { id: randomUUID(), ...data };
}

module.exports = { createProject };"},
    {"path": "src/modules/members/routes.js", "content": "const express = require('express');
const { addMember } = require('./service');
const router = express.Router({ mergeParams: true });

router.post('/', async (req, res) => {
  const member = await addMember(req.params.projectId, req.body);
  if (member) {
    res.status(201).json({ member });
  } else {
    res.status(409).json({ error: { code: 'DUPLICATE', message: 'Member already exists' } });
  }
});

module.exports = router;"},
    {"path": "src/modules/members/service.js", "content": "const members = {};

async function addMember(projectId, data) {
  if (members[projectId] && members[projectId].includes(data.userId)) {
    return null;
  }
  members[projectId] = members[projectId] || [];
  members[projectId].push(data.userId);
  return { userId: data.userId, role: data.role };
}

module.exports = { addMember };"},
    {"path": "src/modules/tasks/routes.js", "content": "const express = require('express');
const { createTask } = require('./service');
const router = express.Router({ mergeParams: true });

router.post('/', async (req, res) => {
  const task = await createTask(req.params.projectId, req.body);
  if (task) {
    res.status(201).json({ task });
  } else {
    res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
});

module.exports = router;"},
    {"path": "src/modules/tasks/service.js", "content": "const projects = {};

async function createTask(projectId, data) {
  if (!projects[projectId]) {
    return null;
  }
  return { id: randomUUID(), ...data };
}

module.exports = { createTask };"},
    {"path": "src/modules/comments/routes.js", "content": "const express = require('express');
